"use strict";function search(e,n){for(let t=0,r=e.length-1;t<=r;){const i=(t+r)/2|0;if(n<=e[i].range[0]){if(i===t)return i;r=i}else t=i+1}return e.length}function getFirstIndex(e,n,t){if(-1===t)return 0;if(t in n)return n[t];if(t-1 in n){const r=n[t-1],i=e[r];return i?i.range[0]>=t?r:r+1:e.length}return 0===t?0:e.length}function getLastIndex(e,n,t){if(-1===t)return e.length-1;if(t in n)return n[t]-1;if(t-1 in n){const r=n[t-1],i=e[r];return i?i.range[1]>t?r-1:r:e.length-1}return 0===t?-1:e.length-1}module.exports={search:search,getFirstIndex:getFirstIndex,getLastIndex:getLastIndex};